How-To-Repeat: 1. Enable telnetd on localhost.
2. Compile program a.c

#include <stdio.h>
#include <stdlib.h>
#include <err.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <termios.h>
#include <libutil.h>

int
main(int argc, char *argv[], char *envp[])
{
        pid_t pid;
        int fd;

        pid = forkpty(&fd, 0, 0, 0);
        if (!pid) {
                execl("/usr/bin/telnet", "telnet", argv[1], 0);
                err(1, "telnet %s", argv[1]);
        }
        if (pid < 0)
                err(1, "forkpty()");
        if (dup2(1, 2) < 0)
                err(1, "dup2(1, 2)");
        if (dup2(fd, 0) < 0)
                err(1, "dup2(fd, 0)");
        if (dup2(fd, 1) < 0)
                err(1, "dup2(fd, 1)");
        close(fd);
        *++argv = "chat";
        execve("/usr/bin/chat", argv, envp);
        err(1, "chat");
}

